import { Link } from "react-router-dom";

const POSTS = [
  {
    slug: "routine-minimaliste",
    title: "Une routine minimaliste qui fonctionne",
    excerpt: "Trois étapes suffisent souvent : nettoyer, hydrater, protéger. Comment choisir sans se perdre.",
    date: "28 mars 2026",
  },
  {
    slug: "hydratation-hiver",
    title: "Hydratation en période sèche",
    excerpt: "Textures, fréquence et petits gestes pour éviter la tiraillement sans surcharger la peau.",
    date: "15 mars 2026",
  },
  {
    slug: "spf-quotidien",
    title: "Pourquoi le SPF au quotidien",
    excerpt: "Même par temps couvert, les UV impactent l’éclat et le vieillissement cutané. Nos repères simples.",
    date: "2 mars 2026",
  },
];

export default function BlogBeaute() {
  return (
    <div style={{ background: "#fff" }}>
      <div style={{ background: "#EEF3EC", borderBottom: "1px solid #D4E8CF", padding: "16px 20px" }}>
        <div style={{ maxWidth: 1280, margin: "0 auto" }}>
          <span style={{ fontSize: 12, color: "#666" }}>Badee Beauty › Blog beauté</span>
          <h1 style={{ fontFamily: "'Josefin Sans',sans-serif", fontWeight: 700, fontSize: 20, letterSpacing: ".05em", textTransform: "uppercase", marginTop: 6 }}>
            Blog beauté
          </h1>
        </div>
      </div>
      <div style={{ maxWidth: 900, margin: "0 auto", padding: "40px 20px 56px" }}>
        <p style={{ fontSize: 14, color: "#666", lineHeight: 1.7, marginBottom: 32 }}>
          Conseils, routines et actus autour des soins Badee Beauty. De nouveaux articles paraissent régulièrement.
        </p>
        <div style={{ display: "grid", gap: 20 }}>
          {POSTS.map((post) => (
            <article
              key={post.slug}
              style={{
                border: "1px solid #E0E0E0",
                borderRadius: 6,
                padding: "22px 20px",
                transition: "border-color .2s, box-shadow .2s",
              }}
            >
              <time style={{ fontSize: 11, color: "#999", letterSpacing: ".06em", textTransform: "uppercase" }}>{post.date}</time>
              <h2 style={{ fontFamily: "'Josefin Sans',sans-serif", fontWeight: 700, fontSize: 17, marginTop: 8, marginBottom: 10, color: "#1a1a1a" }}>
                {post.title}
              </h2>
              <p style={{ fontSize: 14, color: "#555", lineHeight: 1.75, marginBottom: 14 }}>{post.excerpt}</p>
              <Link
                to="/products"
                style={{
                  fontSize: 12,
                  fontFamily: "'Josefin Sans',sans-serif",
                  fontWeight: 700,
                  letterSpacing: ".06em",
                  textTransform: "uppercase",
                  color: "#D6247F",
                  textDecoration: "none",
                }}
              >
                Découvrir nos soins →
              </Link>
            </article>
          ))}
        </div>
      </div>
    </div>
  );
}
